156	// PreMergeChecksReason is the canonical Reason prefix written onto preserved
157	// landings whose preservation was triggered by the pre-merge checks gate.
158	// Callers (status classifiers, dashboards) match on this prefix to bucket
159	// pre-merge-checks misses apart from generic merge conflicts or gate failures.
160	const PreMergeChecksReason = "pre-merge checks blocked"
161	
162	// AppendPreMergeChecksEvents records one bead event per honoured bypass
163	// (kind=checks-bypass) and, when blocked, both the compatibility
164	// checks-blocked event plus a structured pre_merge_check_failed evidence event
165	// for each blocking check. Best-effort: append failures are returned as the
166	// first error encountered so callers can decide whether to surface or log.
167	//
168	// actor and source are forwarded onto every appended event so the audit
169	// trail attributes the gate decision to the right worker / loop session.
170	func AppendPreMergeChecksEvents(store BeadEventAppender, beadID string, outcome *PreMergeChecksOutcome, actor, source string, now time.Time) error {
171		if store == nil || outcome == nil {
172			return nil
173		}
174		var firstErr error
175		for _, e := range outcome.Bypassed {
176			body := fmt.Sprintf("name=%s\nreason=%s", e.Name, e.Reason)
177			if e.Bead != "" {
178				body += "\nbead=" + e.Bead
179			}
180			ev := bead.BeadEvent{
181				Kind:      "checks-bypass",
182				Summary:   fmt.Sprintf("pre-merge check %q bypassed", e.Name),
183				Body:      body,
184				Actor:     actor,
185				Source:    source,
186				CreatedAt: now,
187			}
188			if err := store.AppendEvent(beadID, ev); err != nil && firstErr == nil {
189				firstErr = err
190			}
191		}
192		if outcome.Blocked {
193			for _, r := range outcome.Results {
194				if r.Status != checks.StatusBlock && r.Status != checks.StatusError {
195					continue
196				}
197				body := fmt.Sprintf("name=%s\nstatus=%s", r.Name, r.Status)
198				if r.Message != "" {
199					body += "\nmessage=" + r.Message
200				}
201				ev := bead.BeadEvent{
202					Kind:      "checks-blocked",
203					Summary:   fmt.Sprintf("pre-merge check %q returned %s", r.Name, r.Status),
204					Body:      body,
205					Actor:     actor,
206					Source:    source,
207					CreatedAt: now,
208				}
209				if err := store.AppendEvent(beadID, ev); err != nil && firstErr == nil {
210					firstErr = err
211				}
212				evidence := bead.BeadEvent{
213					Kind:      "pre_merge_check_failed",
214					Summary:   fmt.Sprintf("%s check=%s status=%s", PreMergeChecksReason, r.Name, r.Status),
215					Body:      preMergeCheckFailedEventBody(outcome, r),
216					Actor:     actor,
217					Source:    source,
218					CreatedAt: now,
219				}
220				if err := store.AppendEvent(beadID, evidence); err != nil && firstErr == nil {
221					firstErr = err
222				}
223			}
224		}
225		return firstErr
226	}
