228	func preMergeCheckFailedEventBody(outcome *PreMergeChecksOutcome, r checks.Result) string {
229		lines := []string{
230			"check_name=" + r.Name,
231			"status=" + string(r.Status),
232			fmt.Sprintf("exit_code=%d", r.ExitCode),
233		}
234		if outcome != nil {
235			if outcome.AttemptID != "" {
236				lines = append(lines, "attempt_id="+outcome.AttemptID)
237			}
238			if outcome.BaseRev != "" {
239				lines = append(lines, "base_rev="+outcome.BaseRev)
240			}
241			if outcome.ResultRev != "" {
242				lines = append(lines, "result_rev="+outcome.ResultRev)
243			}
244			if outcome.EvidenceDir != "" {
245				lines = append(lines, "evidence_dir="+filepath.ToSlash(outcome.EvidenceDir))
246			}
247		}
248		if r.Message != "" {
249			lines = append(lines, "message="+eventExcerpt(r.Message))
250			lines = append(lines, "output="+eventExcerpt(r.Message))
251		}
252		if r.Stderr != "" {
253			lines = append(lines, "stderr_tail="+eventExcerpt(r.Stderr))
254			if r.Message == "" {
255				lines = append(lines, "output="+eventExcerpt(r.Stderr))
256			}
257		}
258		if len(r.Violations) > 0 {
259			lines = append(lines, fmt.Sprintf("violations=%d", len(r.Violations)))
260		}
261		return strings.Join(lines, "\n")
262	}
