273	// PreserveAfterPreMergeChecks is the canonical preservation step invoked when
274	// RunPreMergeChecks returned Blocked=true. It writes refs/ddx/iterations/...
275	// pointing at the worker's resultRev (so the work survives for later
276	// inspection) and returns the synthetic LandResult{Status:"preserved"} that
277	// callers can hand to ApplyLandResultToExecuteBeadResult.
278	//
279	// The preserved iteration ref naming follows the existing
280	// landIterationRef convention so operators see a single ref namespace
281	// regardless of which gate triggered the preservation.
282	func PreserveAfterPreMergeChecks(projectRoot string, res *ExecuteBeadResult, outcome *PreMergeChecksOutcome, gitOps OrchestratorGitOps) (*LandResult, error) {
283		if outcome == nil || !outcome.Blocked {
284			return nil, fmt.Errorf("pre-merge checks: preserve called without blocked outcome")
285		}
286		if gitOps == nil {
287			gitOps = &RealOrchestratorGitOps{}
288		}
289		ref := PreserveRef(res.BeadID, res.BaseRev)
290		if err := gitOps.UpdateRef(projectRoot, ref, res.ResultRev); err != nil {
291			return nil, fmt.Errorf("pre-merge checks: preserving %s: %w", ref, err)
292		}
293		return &LandResult{
294			Status:      "preserved",
295			PreserveRef: ref,
296			Reason:      outcome.Reason,
297		}, nil
298	}
