425	func ctxSleep(ctx context.Context, d time.Duration) error {
426		if d <= 0 {
427			return nil
428		}
429		t := time.NewTimer(d)
430		defer t.Stop()
431		select {
432		case <-ctx.Done():
433			return ctx.Err()
434		case <-t.C:
435			return nil
436		}
437	}
