439	func evaluateRateLimitAttempt(report Report, cfg RateLimitRetryConfig, attempt int, elapsed, budget time.Duration) (RateLimitWaitDecision, time.Duration) {
440		if cfg.Budget < 0 || budget < 0 {
441			return RateLimitWaitDecision{ShouldRetry: false}, 0
442		}
443		if !IsRateLimitReport(&report) {
444			return RateLimitWaitDecision{ShouldRetry: false}, 0
445		}
446	
447		retryAfter := ExtractRetryAfterFromStderr(report.Stderr, cfg.Now())
448		decision := cfg.Evaluator(retryAfter, attempt, elapsed, budget, cfg.PerWaitCap)
449		if !decision.ShouldRetry {
450			decision.Reason = RateLimitBudgetExhaustedReason
451		}
452		return decision, retryAfter
453	}
454	
455	func EvaluateRateLimitWait(retryAfter time.Duration, attempt int, elapsed, budget, perWaitCap time.Duration) RateLimitWaitDecision {
456		if budget > 0 && elapsed >= budget {
457			return RateLimitWaitDecision{ShouldRetry: false, Reason: RateLimitBudgetExhaustedReason}
458		}
459	
460		var wait time.Duration
461		var source string
462		if retryAfter > 0 {
463			wait = retryAfter
464			source = "retry-after"
465		} else {
466			idx := attempt - 1
467			if idx < 0 {
468				idx = 0
469			}
470			if idx >= len(rateLimitBackoffSchedule) {
471				idx = len(rateLimitBackoffSchedule) - 1
472			}
473			wait = rateLimitBackoffSchedule[idx]
474			source = "exponential-backoff"
475		}
476	
477		if perWaitCap > 0 && wait > perWaitCap {
478			wait = perWaitCap
479		}
480	
481		if budget > 0 && elapsed+wait > budget {
482			remaining := budget - elapsed
483			if remaining <= 0 {
484				return RateLimitWaitDecision{ShouldRetry: false, Reason: RateLimitBudgetExhaustedReason}
485			}
486			wait = remaining
487		}
488	
489		return RateLimitWaitDecision{ShouldRetry: true, Wait: wait, Source: source}
490	}
