511	func hasIsolated429(s string) bool {
512		for i := 0; i+3 <= len(s); i++ {
513			if s[i:i+3] != "429" {
514				continue
515			}
516			if i > 0 {
517				c := s[i-1]
518				if c >= '0' && c <= '9' {
519					continue
520				}
521			}
522			if i+3 < len(s) {
523				c := s[i+3]
524				if c >= '0' && c <= '9' {
525					continue
526				}
527			}
528			return true
529		}
530		return false
531	}
