543		}
544		if t, err := http.ParseTime(value); err == nil {
545			d := t.Sub(now)
546			if d < 0 {
547				return 0
548			}
549			return d
550		}
551		if d, err := time.ParseDuration(value); err == nil && d >= 0 {
