557	func ExtractRetryAfterFromStderr(stderr string, now time.Time) time.Duration {
558		if stderr == "" {
559			return 0
560		}
561		lower := strings.ToLower(stderr)
562		for _, marker := range []string{"retry-after:", "retry_after=", "retry-after ", "retry after "} {
563			idx := strings.Index(lower, marker)
564			if idx < 0 {
565				continue
566			}
567			rest := stderr[idx+len(marker):]
568			if eol := strings.IndexAny(rest, "\r\n"); eol >= 0 {
569				rest = rest[:eol]
570			}
571			rest = strings.TrimSpace(rest)
572			rest = strings.Trim(rest, "\"',")
573			if d := ParseRetryAfter(rest, now); d > 0 {
574				return d
575			}
576		}
577		return 0
578	}
