61	func investigationRetryInitialMinPower(b *bead.Bead, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, agent.ExecuteBeadReport, bool) {
62		if tier, ok := triageTierHint(b); !ok || tier != policyescalation.TierSmart {
63			return baseMinPower, agent.ExecuteBeadReport{}, false
64		}
65		floor, err := highestViableEscalationFloor(ladder)
66		if err != nil {
67			return baseMinPower, smartRouteUnavailableReport(b, baseMinPower, maxPower, err), true
68		}
69		if baseMinPower > floor {
70			return baseMinPower, smartRouteUnavailableReport(b, baseMinPower, maxPower, nil), true
71		}
72		if maxPower > 0 && floor >= maxPower {
73			return baseMinPower, smartRouteUnavailableReport(b, floor, maxPower, nil), true
74		}
75		return floor, agent.ExecuteBeadReport{}, false
76	}
