78	func triageTierHint(b *bead.Bead) (policyescalation.ModelTier, bool) {
79		if b == nil || b.Extra == nil {
80			return "", false
81		}
82		raw, ok := b.Extra[agent.TriageTierHintKey]
83		if !ok {
84			return "", false
85		}
86		switch strings.ToLower(strings.TrimSpace(fmt.Sprint(raw))) {
87		case string(policyescalation.TierSmart):
88			return policyescalation.TierSmart, true
89		case string(policyescalation.TierStandard):
90			return policyescalation.TierStandard, true
91		case string(policyescalation.TierCheap):
92			return policyescalation.TierCheap, true
93		default:
94			return "", false
95		}
96	}
