98	func smartRouteUnavailableReport(b *bead.Bead, minPower, maxPower int, cause error) agent.ExecuteBeadReport {
99		beadID := ""
100		if b != nil {
101			beadID = b.ID
102		}
103		detail := fmt.Sprintf("smart retry route unavailable: no viable routing candidate satisfies requested MinPower %d", minPower)
104		if maxPower > 0 {
105			detail += fmt.Sprintf(" and MaxPower %d", maxPower)
106		}
107		if cause != nil {
108			detail += ": " + cause.Error()
109		}
110		return agent.ExecuteBeadReport{
111			BeadID:        beadID,
112			Status:        agent.ExecuteBeadStatusExecutionFailed,
113			Detail:        detail,
114			OutcomeReason: agent.FailureModeNoViableProvider,
115		}
116	}
