118	func runEscalatingSingleTierAttempts(
119		ctx context.Context,
120		initialMinPower int,
121		ladder escalationFloorFinder,
122		attempt func(context.Context, int) (agent.ExecuteBeadReport, error),
123		recordAttempt func(agent.ExecuteBeadReport),
124	) (agent.ExecuteBeadReport, error) {
125		minPower := initialMinPower
126		for {
127			report, err := attempt(ctx, minPower)
128			if recordAttempt != nil && report.BeadID != "" {
129				recordAttempt(report)
130			}
131			if err != nil {
132				return report, err
133			}
134			if report.Disrupted || isBudgetExhaustedFailure(report) || !policyescalation.ShouldEscalate(report.Status) || policyescalation.IsInfrastructureFailure(report.Status, report.Detail) {
135				return report, nil
136			}
137			basis := minPower
138			if report.ActualPower > 0 {
139				basis = report.ActualPower
140			}
141			nextPower, nextErr := nextEscalationFloor(ladder, basis)
142			if nextErr != nil {
143				return report, nil
144			}
145			minPower = nextPower
146		}
147	}
