// isDirtyBuild reports whether the binary was built from a modified working tree.
// It reads vcs.modified from Go build info when available, then falls back to
// git status for dev builds where the build info lacks embedded VCS data.
func isDirtyBuild() bool {
	info, ok := debug.ReadBuildInfo()
	if ok {
		for _, s := range info.Settings {
			if s.Key == "vcs.modified" {
				return s.Value == "true"
			}
		}
		// Build info was available but had no vcs.modified: check whether any
		// vcs settings were present at all. If they were, the clean state was
		// explicitly recorded. If not, fall through to the git fallback.
		for _, s := range info.Settings {
			if s.Key == "vcs.revision" {
				return false
			}
		}
	}
	// Fall back to git status for cross-filesystem worktrees and similar setups
	// where Go cannot embed VCS info at build time.
	out, err := exec.Command("git", "status", "--porcelain").Output()
	if err != nil {
		return false
	}
	return len(strings.TrimSpace(string(out))) > 0
}

